392:     auto n = at::symint::size<T>(input, 0);
393:     if (numel_input / n > int_max) {
394:       return true;
395:     }
396:     // output size can not be reduced to the range of int by splitting the batch dim
397:     T outsize = 1;
398:     if (transposed) {
399:       auto o = conv_input_size(at::symint::sizes<T>(input), at::symint::sizes<T>(weight), padding, output_padding, stride, dilation, groups);
400:       outsize = c10::multiply_integers(o.begin() + 1, o.end());
401:     } else {
402:       auto o = conv_output_size(at::symint::sizes<T>(input), at::symint::sizes<T>(weight), padding, stride, dilation);
403:       outsize = c10::multiply_integers(o.begin() + 1, o.end());
404:     }
405:     return outsize > int_max;
