400: inline bool mkldnn_conv_use_channels_last(const at::Tensor& input, const at::Tensor& weight) {
401: 
402:   // disable NHWC for float64 input.
403:   if (input.scalar_type() == at::kDouble ||
404:       weight.scalar_type() == at::kDouble) {
405:     return false;
406:   }
407: 
408:   // disable NHWC for MkldnnCPU tensor.
409:   if (input.is_mkldnn() || weight.is_mkldnn()) {
410:     return false;
