412: 
413:   auto input_memory_format = input.suggest_memory_format();
414:   auto weight_memory_format = weight.suggest_memory_format();
415: 
416:   bool can_use_mkldnn_channels_last_2d =
417:       (input_memory_format  == at::MemoryFormat::ChannelsLast) ||
418:       (weight_memory_format == at::MemoryFormat::ChannelsLast);
419: 
420:   bool can_use_mkldnn_channels_last_3d =
421:       (input_memory_format  == at::MemoryFormat::ChannelsLast3d) ||
422:       (weight_memory_format == at::MemoryFormat::ChannelsLast3d);
