450:   auto is_channel_last = [](const at::Tensor& t) {
451:     auto fmt = t.suggest_memory_format();
452:     return fmt == at::MemoryFormat::ChannelsLast || fmt == at::MemoryFormat::ChannelsLast3d;
453:   };
