103: template<typename T>
104: struct InvStd {
105:   T operator()(T var, double epsilon) const {
106:     T invstd = 0;
107:     if (var != static_cast<T>(0) || epsilon != static_cast<T>(0)) {
108:       invstd = static_cast<T>(1) / std::sqrt(var + epsilon);
109:     }
110:     return invstd;
111:   }
112: };
