199: template<typename scalar_t, typename param_t, template<typename T> class VarTransform>
200: static std::tuple<Tensor,Tensor> batch_norm_cpu_update_stats_template(
201:     const Tensor& input, const Tensor& running_mean, const Tensor& running_var,
202:     double momentum, double eps, Tensor& save_mean, Tensor& save_var_transform) {
203: 
204:   using accscalar_t = at::acc_type<scalar_t, false>;
205: 
206:   int64_t n_input = input.size(1);
207:   TORCH_CHECK(input.numel() != 0, "input tensor must have at least one element, but got input_sizes = ", input.sizes());
208:   int64_t n = input.numel() / n_input;
209: 
210:   bool all_contiguous = is_contiguous(input);
211:   constexpr bool mixed_type = !std::is_same_v<scalar_t, param_t>;
212:   // Using float data type for Half _var_sum in batchnorm stats updating on CPU
213:   // to avoid _var_sum overflow since the representation range of Half is small.
214:   using opmath_t = std::conditional_t<std::is_same_v<param_t, at::Half>, at::opmath_type<param_t>, param_t>;
215:   auto dtype = mixed_type ? kFloat : input.scalar_type();
216:   if (dtype == kHalf) {
217:     dtype = kFloat;
218:   }
219: 
220:   auto save_mean_a = save_mean.accessor<param_t, 1>();
221:   auto save_var_transform_a = save_var_transform.accessor<param_t, 1>();
222: 
223:   auto running_mean_a = conditional_accessor_1d<param_t>(running_mean);
224:   auto running_var_a = conditional_accessor_1d<param_t>(running_var);
225: 
226:   if (all_contiguous) {
227:     auto _mean = at::empty({n_input}, input.options().dtype(dtype));
228:     auto _var_sum = at::empty({n_input}, input.options().dtype(dtype));
229:     auto _mean_a = _mean.accessor<opmath_t, 1>();
230:     auto _var_sum_a = _var_sum.accessor<opmath_t, 1>();
231:     auto momentum_ = static_cast<opmath_t>(momentum);
232: 
233:     batch_norm_cpu_collect_stats_stub(kCPU, _mean, _var_sum, input);
234: 
235:     parallel_for(0, n_input, 1, [&](int64_t b_begin, int64_t b_end) {
236:       for (const auto f : c10::irange(b_begin, b_end)) {
237:         save_mean_a[f] = _mean_a[f];
238:         save_var_transform_a[f] = VarTransform<accscalar_t>{}(_var_sum_a[f] / n, eps);
239: 
240:         if (running_mean.defined()) {
241:           running_mean_a[f] = momentum_ * _mean_a[f] + (1 - momentum_) * running_mean_a[f];
242:         }
243:         if (running_var.defined()) {
244:           accscalar_t unbiased_var = _var_sum_a[f] / (n - 1);
245:           running_var_a[f] = momentum_ * unbiased_var + (1 - momentum_) * running_var_a[f];
246:         }
247:       }
248:     });
249: 
250:     return std::make_tuple(save_mean, save_var_transform);
251:   }
252: 
253:   // non-contiguous path
254:   auto channel_stride = input.strides()[1];
255:   auto in_data = input.data_ptr<scalar_t>();
256:   auto reduce_iter = TensorIteratorConfig()
257:       .add_input(input)
258:       .resize_outputs(false)
259:       .declare_static_shape(input.sizes(), /*squash_dims=*/1)
260:       .check_all_same_dtype(false)
261:       .promote_inputs_to_common_dtype(false)
262:       .build();
263: 
264:   parallel_for(0, n_input, 1, [&](int64_t b_begin, int64_t b_end) {
265:     TensorIterator iter(reduce_iter);
266:     for (const auto f : c10::irange(b_begin, b_end)) {
267:       // compute variance per input
268:       iter.unsafe_replace_operand(0, in_data + channel_stride * f);
269:       accscalar_t var_sum = 0;
270:       auto mean = static_cast<accscalar_t>(save_mean_a[f]);
271:       cpu_serial_kernel(iter, [&](const scalar_t i) -> void {
272:         var_sum += (i - mean) * (i - mean);
273:       });
274:       save_var_transform_a[f] = VarTransform<accscalar_t>{}(var_sum / n, eps);
275: 
276:       // update running averages
277:       if (running_mean.defined()) {
278:         running_mean_a[f] = momentum * mean + (1 - momentum) * running_mean_a[f];
279:       }
280:       if (running_var.defined()) {
281:         accscalar_t unbiased_var = var_sum / (n - 1);
282:         running_var_a[f] = momentum * unbiased_var + (1 - momentum) * running_var_a[f];
283:       }
284:     }
285:   });
286:   return std::make_tuple(save_mean, save_var_transform);
287: }
288: 
289: template<typename scalar_t, typename param_t, template<typename T> class VarTransform>
290: static std::tuple<Tensor,Tensor> batch_norm_cpu_update_stats_template(
291:     const Tensor& input, const Tensor& running_mean, const Tensor& running_var,
292:     double momentum, double eps) {
293:   int64_t n_input = input.size(1);
294:   const int64_t ndim = input.dim();
295:   DimVector reduce_dims(ndim - 1);
296:   reduce_dims[0] = 0;
297:   for (const auto i : c10::irange(2, ndim)) {
298:     reduce_dims[i - 1] = i;
299:   }
300: 
301:   constexpr bool mixed_type = !std::is_same_v<scalar_t, param_t>;
302:   const auto dtype = mixed_type ? kFloat : input.scalar_type();
303:   Tensor save_mean = is_contiguous(input) ? at::empty({n_input}, input.options().dtype(dtype)) : at::mean(input, /*dim=*/reduce_dims, /*keepdim=*/false, dtype);
304:   Tensor save_var_transform = at::empty({n_input}, input.options().dtype(dtype));
305:   return batch_norm_cpu_update_stats_template<scalar_t, param_t, VarTransform>(input, running_mean, running_var, momentum, eps, save_mean, save_var_transform);
306: }
