308: template<typename scalar_t, typename param_t>
309: static std::tuple<Tensor, Tensor, Tensor> batch_norm_backward_cpu_template(
310:     const Tensor& grad_out_, const Tensor& input, const Tensor& weight,
311:     const Tensor& running_mean, const Tensor& running_var, const Tensor& save_mean, const Tensor& save_invstd,
312:     bool train, double eps, std::array<bool,3> grad_input_mask) {
313: 
314:   using accscalar_t = at::acc_type<scalar_t, false>;
315: 
316:   constexpr bool mixed_type = !std::is_same_v<scalar_t, param_t>;
317:   const auto dtype = mixed_type ? kFloat : input.scalar_type();
318: 
319:   Tensor grad_input;
320:   Tensor grad_weight;
321:   Tensor grad_bias;
322:   if (grad_input_mask[0]) {
323:     grad_input = at::empty_like(input, input.suggest_memory_format());
324:   }
325:   if (grad_input_mask[1]) {
326:     grad_weight = at::empty({input.size(1)}, input.options().dtype(dtype));
327:   }
328:   if (grad_input_mask[2]) {
329:     grad_bias = at::empty({input.size(1)}, input.options().dtype(dtype));
330:   }
331: 
332:   // since we are directly manipulating pointers in contiguous path,
333:   // need to make sure input and grad_out have the same memory format.
334:   bool all_contiguous = is_contiguous(input)
335:       && is_contiguous(grad_out_)
336:       && input.suggest_memory_format() == grad_out_.suggest_memory_format();
337: 
338:   if (all_contiguous) {
339:     if (grad_input_mask[0]) {
340:       grad_input = at::empty_like(input, suggest_memory_format_contig(input));
341:     }
342:     batch_norm_cpu_backward_stub(kCPU, grad_input, grad_weight, grad_bias,
343:         grad_out_, input, weight, running_mean, running_var, save_mean, save_invstd, train, eps);
344:     return std::make_tuple(grad_input, grad_weight, grad_bias);
345:   }
346: 
347:   auto weight_a = conditional_accessor_1d<const param_t>(weight);
348:   auto grad_weight_a = conditional_accessor_1d<param_t>(grad_weight);
349:   auto grad_bias_a = conditional_accessor_1d<param_t>(grad_bias);
350: 
351:   int64_t n_input = input.size(1);
352:   int64_t n = input.numel() / n_input;
353: 
354:   auto save_mean_a = conditional_accessor_1d<const param_t>(save_mean);
355:   auto save_invstd_a = conditional_accessor_1d<const param_t>(save_invstd);
356: 
357:   auto running_mean_a = conditional_accessor_1d<const param_t>(running_mean);
358:   auto running_var_a = conditional_accessor_1d<const param_t>(running_var);
359: 
360:   const int64_t ndim = input.dim();
361: 
362:   // Reduce all dimensions except dim=1
363:   DimVector reduce_dims(ndim - 1);
364:   reduce_dims[0] = 0;
365:   for (const auto i : c10::irange(2, ndim)) {
366:     reduce_dims[i - 1] = i;
367:   }
368:   // Using float data type for Half sum to avoid overflow
369:   // since the representation range of Half is small.
370:   auto sum = grad_out_.scalar_type() == kHalf
371:       ? at::sum(grad_out_.to(ScalarType::Float), /*dim=*/reduce_dims)
372:       : at::sum(grad_out_, /*dim=*/reduce_dims);
373:   using sum_t = std::conditional_t<std::is_same_v<scalar_t, at::Half>, float, scalar_t>;
374:   auto sum_a = sum.accessor<sum_t, 1>();
375: 
376:   auto reduce_iter = TensorIteratorConfig()
377:       .add_const_input(input)
378:       .add_const_input(grad_out_)
379:       .resize_outputs(false)
380:       .declare_static_shape(input.sizes(), /*squash_dims=*/1)
381:       .build();
382: 
383:   TensorIterator unary_iter;
384:   TensorIterator binary_iter;
385:   if (grad_input_mask[0]) {
386:     unary_iter.build(
387:         TensorIteratorConfig()
388:         .add_output(grad_input)
389:         .add_const_input(train ? input : grad_out_)
390:         .resize_outputs(false)
391:         .declare_static_shape(input.sizes(), /*squash_dims=*/1));
392: 
393:     if (train) {
394:       binary_iter.build(
395:           TensorIteratorConfig()
396:           .add_output(grad_input)
397:           .add_input(grad_input)
398:           .add_const_input(grad_out_)
399:           .resize_outputs(false)
400:           .declare_static_shape(input.sizes(), /*squash_dims=*/1));
401:     }
402:   }
403: 
404:   auto in_channel_stride = input.strides()[1];
405:   auto in_data = input.const_data_ptr<scalar_t>();
406:   auto grad_in_channel_stride = grad_input_mask[0] ? grad_input.strides()[1] : 0;
407:   auto grad_in_data = grad_input_mask[0] ? grad_input.mutable_data_ptr<scalar_t>() : nullptr;
408:   auto grad_out_channel_stride = grad_out_.strides()[1];
409:   auto grad_out_data = grad_out_.const_data_ptr<scalar_t>();
410: 
411:   parallel_for(0, n_input, 1, [&](int64_t b_begin, int64_t b_end) {
412:       TensorIterator reduce_iter_local(reduce_iter);
413:       TensorIterator unary_iter_local(unary_iter);
414:       TensorIterator binary_iter_local(binary_iter);
415: 
416:       for (const auto f : c10::irange(b_begin, b_end)) {
417:         param_t w = weight.defined() ? weight_a[f] : param_t(1);
418: 
419:         param_t mean{}, invstd{};
420:         if (train) {
421:           mean = save_mean_a[f];
422:           invstd = save_invstd_a[f];
423:         } else {
424:           mean = running_mean_a[f];
425:           invstd = 1 / std::sqrt(running_var_a[f] + eps);
426:         }
427: 
428:         // dot product of the Q(X) and gradOutput
429:         accscalar_t dotp = 0;
430:         reduce_iter_local.unsafe_replace_operand(
431:             0, const_cast<scalar_t*>(in_data + f * in_channel_stride));
432:         reduce_iter_local.unsafe_replace_operand(
433:             1, const_cast<scalar_t*>(grad_out_data + f * grad_out_channel_stride));
434: 
435:         cpu_serial_kernel(reduce_iter_local, [&](const scalar_t i, const scalar_t go) -> void {
436:           dotp += (i - mean) * go;
437:         });
438: 
439:         if (grad_input_mask[0]) {
440:           if (train) {
441:             // when in training mode
442:             // Q(X) = X - E[x] ; i.e. input centered to zero mean
443:             // Y = Q(X) / sigma    ; i.e. BN output before weight and bias
444:             // dL/dX = (Q(dL/dY) - dot(Y, dL/dY) * Y) / sigma * w
445: 
446:             // projection of gradOutput on to output scaled by std
447:             scalar_t k = (scalar_t) dotp * invstd * invstd / n;
448:             {
449:               unary_iter_local.unsafe_replace_operand(
450:                   0, grad_in_data + f * grad_in_channel_stride);
451:               unary_iter_local.unsafe_replace_operand(
452:                   1, const_cast<scalar_t*>(in_data + f * in_channel_stride));
453:               cpu_serial_kernel(unary_iter_local, [&](const scalar_t i) -> scalar_t {
454:                 return (i - mean) * k;
455:               });
456:             }
457: 
458:             scalar_t grad_mean = sum_a[f] / n;
459:             {
460:               auto gI_data = grad_in_data + f * grad_in_channel_stride;
461:               binary_iter_local.unsafe_replace_operand(0, gI_data);
462:               binary_iter_local.unsafe_replace_operand(1, gI_data);
463:               binary_iter_local.unsafe_replace_operand(
464:                   2, const_cast<scalar_t*>(grad_out_data + f * grad_out_channel_stride));
465:               cpu_serial_kernel(binary_iter_local, [&](scalar_t gi, scalar_t go) -> scalar_t {
466:                 return (go - grad_mean - gi) * invstd * w;
467:               });
468:             }
469:           } else {
470:             // when in evaluation mode
471:             // Q(X) = X - running_mean  ; i.e. input centered to zero mean
472:             // Y = Q(X) / running_std    ; i.e. BN output before weight and bias
473:             // dL/dX = w / running_std
474:             {
475:               unary_iter_local.unsafe_replace_operand(
476:                   0, grad_in_data + f * grad_in_channel_stride);
477:               unary_iter_local.unsafe_replace_operand(
478:                   1, const_cast<scalar_t*>(grad_out_data + f * grad_out_channel_stride));
479:               cpu_serial_kernel(unary_iter_local, [&](const scalar_t i) -> scalar_t {
480:                 return i * invstd * w;
481:               });
482:             }
483:           }
484:         }
485:         if (grad_input_mask[1]) {
486:           grad_weight_a[f] = dotp * invstd;
487:         }
488: 
489:         if (grad_input_mask[2]) {
490:           grad_bias_a[f] = sum_a[f];
491:         }
492:       }
493:     });
494:   return std::make_tuple(grad_input, grad_weight, grad_bias);
495: }
