497: BatchNormBackend _select_batch_norm_backend(
498:     const Tensor& input, const Tensor& weight, const Tensor& bias, const Tensor& running_mean,
499:     const Tensor& running_var, bool training, double eps) {
500: 
501:   auto& ctx = at::globalContext();
502:   bool cudnn_enabled = ctx.userEnabledCuDNN();
503: 
504:   if (
505:       input.is_cuda()
506:       && input.scalar_type() != at::kBFloat16 && weight.scalar_type() != at::kBFloat16
507:       && (input.scalar_type() != at::kHalf
508:         || weight.scalar_type() == at::kFloat)
509:       && weight.defined() && bias.defined()
510:       && ((running_mean.defined() && running_var.defined())
511:         || (!running_mean.defined() && !running_var.defined() && training))
512:       && (input.dim() >= 3)
513:       && ((input.sym_size(0) <= 880801 && training) // spatial, training
514:           ||(input.sym_size(0) <= 65535 && !training)) //spatial, eval
515:       && detail::getCUDAHooks().compiledWithCuDNN()
516:       && eps >= detail::getCUDAHooks().batchnormMinEpsilonCuDNN()
517:       && cudnn_enabled && detail::getCUDAHooks().versionCuDNN() >= 5110L
518:       && input.sym_numel() < std::numeric_limits<std::int32_t>::max() // some cuDNN kernels have 32-bit indexing limitations
519:   ) {
520:     return BatchNormBackend::Cudnn;
521:   }
